// src/pages/ResultsPage.js
import React, { useEffect, useRef, useState } from "react";
import { saveSession } from "../utils/firebase";
import "./ResultsPage.css";

function ScoreRing({ score }) {
  const r = 54;
  const circ = 2 * Math.PI * r;
  const offset = circ - (score / 100) * circ;
  const color = score >= 80 ? "#4ecca3" : score >= 60 ? "#ffd166" : "#fc6c8f";
  const label = score >= 80 ? "Excellent" : score >= 60 ? "Good" : "Needs Work";

  return (
    <div className="score-ring-wrap">
      <div className="score-ring">
        <svg viewBox="0 0 120 120" width="120" height="120">
          <circle className="score-ring-bg"   cx="60" cy="60" r={r} />
          <circle className="score-ring-fill" cx="60" cy="60" r={r}
            strokeDasharray={circ}
            strokeDashoffset={offset}
            stroke={color}
          />
        </svg>
        <div className="score-ring-text">
          <span className="score-num" style={{ color }}>{score}</span>
          <span className="score-label">/ 100</span>
        </div>
      </div>
      <span className="tag" style={{ background: `${color}22`, color }}>{label}</span>
    </div>
  );
}

function MetricCard({ label, value, unit, note, color = "#7c6cfc" }) {
  return (
    <div className="metric-card card">
      <span className="metric-value" style={{ color }}>{value}</span>
      <span className="metric-unit">{unit}</span>
      <span className="metric-label">{label}</span>
      {note && <span className="metric-note">{note}</span>}
    </div>
  );
}

export default function ResultsPage({ navigate, results }) {
  const { transcript, metrics, feedback, scenario } = results || {};
  const saved = useRef(false);
  const [showTranscript, setShowTranscript] = useState(false);

  useEffect(() => {
    if (!saved.current && metrics) {
      saved.current = true;
      saveSession({ scenario, transcript, metrics, feedback, date: new Date().toISOString() });
    }
  }, []);

  if (!results) return <div className="results-page center"><p>No results found.</p></div>;

  const wpmColor = metrics.wpm >= 120 && metrics.wpm <= 160 ? "#4ecca3" : metrics.wpm > 160 ? "#fc6c8f" : "#ffd166";
  const fillerColor = metrics.totalFillers === 0 ? "#4ecca3" : metrics.totalFillers <= 5 ? "#ffd166" : "#fc6c8f";
  const scoreColor = metrics.score >= 80 ? "#4ecca3" : metrics.score >= 60 ? "#ffd166" : "#fc6c8f";

  return (
    <div className="results-page">
      <nav className="navbar">
        <span className="navbar-logo" onClick={() => navigate("landing")}>CLARIO</span>
        <div className="navbar-links">
          <button className="btn btn-ghost" onClick={() => navigate("dashboard")}>📊 Dashboard</button>
          <button className="btn btn-primary" onClick={() => navigate("practice")}>🎙️ Practice Again</button>
        </div>
      </nav>

      <div className="results-inner">
        {/* Header */}
        <div className="results-header">
          <span className="tag tag-purple">{scenario}</span>
          <h1>Your Results</h1>
          <p className="results-date">{new Date().toLocaleDateString("en-PH", { month: "long", day: "numeric", year: "numeric" })}</p>
        </div>

        {/* Score + Metrics row */}
        <div className="score-row">
          <ScoreRing score={metrics.score} />
          <div className="metrics-grid">
            <MetricCard label="Speech Rate"  value={metrics.wpm}          unit="WPM"    color={wpmColor}    note={metrics.wpm > 160 ? "Try slowing down" : metrics.wpm < 100 ? "Try speeding up" : "Great pace!"} />
            <MetricCard label="Total Words"  value={metrics.totalWords}   unit="words"  color="#a99dff" />
            <MetricCard label="Filler Words" value={metrics.totalFillers} unit="fillers" color={fillerColor} note={metrics.totalFillers > 5 ? "Try pausing instead" : metrics.totalFillers === 0 ? "Perfect!" : "Good job!"} />
            <MetricCard label="Overall Score" value={metrics.score}       unit="/ 100"  color={scoreColor} />
          </div>
        </div>

        {/* Filler word breakdown */}
        {Object.keys(metrics.fillerCounts).length > 0 && (
          <div className="card filler-section">
            <h3 className="section-h3">🔍 Filler Word Breakdown</h3>
            <div className="filler-chips">
              {Object.entries(metrics.fillerCounts).sort((a, b) => b[1] - a[1]).map(([word, count]) => (
                <div key={word} className="filler-chip">
                  <span className="filler-word">"{word}"</span>
                  <span className="filler-count">{count}×</span>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* AI Feedback */}
        <div className="card feedback-card">
          <div className="feedback-header">
            <span className="feedback-icon">🤖</span>
            <div>
              <h3>AI Coaching Feedback</h3>
              <p className="feedback-sub">Personalized insights powered by Claude</p>
            </div>
          </div>
          <div className="feedback-body">
            {feedback.split("\n").filter(Boolean).map((para, i) => (
              <p key={i}>{para}</p>
            ))}
          </div>
        </div>

        {/* Transcript (collapsible) */}
        <div className="card transcript-section">
          <button className="transcript-toggle" onClick={() => setShowTranscript(!showTranscript)}>
            <span>📝 View Transcript</span>
            <span>{showTranscript ? "▲" : "▼"}</span>
          </button>
          {showTranscript && (
            <div className="transcript-body">
              {transcript || "No transcript available."}
            </div>
          )}
        </div>

        {/* Actions */}
        <div className="results-actions">
          <button className="btn btn-primary" onClick={() => navigate("practice")}>
            🎙️ Practice Again
          </button>
          <button className="btn btn-outline" onClick={() => navigate("dashboard")}>
            📈 View Progress
          </button>
        </div>
      </div>
    </div>
  );
}
